     1→import { TRPCError } from "@trpc/server";
     2→import { z } from "zod";
     3→import {
     4→  deleteChat,
     5→  findChatsByProject,
     6→  getChatById,
     7→  updateChatTitle,
     8→} from "@/server/database/repo/postgress-repo-functions/chat.repo";
     9→import { loadChatMessages } from "@/server/database/repo/postgress-repo-functions/chatMessage.repo";
    10→import { createTRPCRouter, protectedProcedure } from "../init";
    11→
    12→export const chatRouter = createTRPCRouter({
    13→  // Get all chats for a project
    14→  getChats: protectedProcedure
    15→    .input(
    16→      z.object({
    17→        projectId: z.string().uuid("Invalid project ID"),
    18→      }),
    19→    )
    20→    .query(async ({ input, ctx }) => {
    21→      // findChatsByProject filters by both projectId AND userId
    22→      // so only chats owned by this user for this project are returned
    23→      const chats = await findChatsByProject(input.projectId, ctx.userId);
    24→      return { chats };
    25→    }),
    26→
    27→  // Get messages for a specific chat
    28→  getMessages: protectedProcedure
    29→    .input(
    30→      z.object({
    31→        chatId: z.string().uuid("Invalid chat ID"),
    32→      }),
    33→    )
    34→    .query(async ({ input, ctx }) => {
    35→      // getChatById filters by chatId AND userId - ownership verified
    36→      const chat = await getChatById({
    37→        chatId: input.chatId,
    38→        userId: ctx.userId,
    39→      });
    40→      if (!chat) {
    41→        throw new TRPCError({
    42→          code: "FORBIDDEN",
    43→          message: "Chat not found or access denied",
    44→        });
    45→      }
    46→
    47→      const messages = await loadChatMessages(chat.id, ctx.userId);
    48→      return { messages };
    49→    }),
    50→  // Update chat title
    51→  updateTitle: protectedProcedure
    52→    .input(
    53→      z.object({
    54→        chatId: z.string().uuid("Invalid chat ID"),
    55→        title: z.string().min(1).max(100),
    56→      }),
    57→    )
    58→    .mutation(async ({ input, ctx }) => {
    59→      // updateChatTitle filters by chatId AND userId - ownership verified
    60→      const chat = await updateChatTitle({
    61→        chatId: input.chatId,
    62→        userId: ctx.userId,
    63→        title: input.title,
    64→      });
    65→
    66→      if (!chat) {
    67→        throw new TRPCError({
    68→          code: "FORBIDDEN",
    69→          message: "Chat not found or access denied",
    70→        });
    71→      }
    72→
    73→      return { chat };
    74→    }),
    75→
    76→  // Delete a chat
    77→  deleteChat: protectedProcedure
    78→    .input(
    79→      z.object({
    80→        chatId: z.string().uuid("Invalid chat ID"),
    81→      }),
    82→    )
    83→    .mutation(async ({ input, ctx }) => {
    84→      // deleteChat filters by chatId AND userId - ownership verified
    85→      const deleted = await deleteChat({
    86→        chatId: input.chatId,
    87→        userId: ctx.userId,
    88→      });
    89→
    90→      if (!deleted) {
    91→        throw new TRPCError({
    92→          code: "FORBIDDEN",
    93→          message: "Chat not found or access denied",
    94→        });
    95→      }
    96→
    97→      return { success: true };
    98→    }),
    99→});
