    27→const handleAxiosError = (axoisErr: AxiosError) => {
    28→  logger.error("[debug] axios error details", {
    29→    status: axoisErr.response?.status,
    30→    statusText: axoisErr.response?.statusText,
    31→    data: axoisErr.response?.data,
    32→    message: axoisErr.message,
    33→  });
    34→
    35→  // Extract actual error message from API response if available
    36→  const responseData = axoisErr.response?.data;
    37→  const actualErrorMessage =
    38→    (responseData &&
    39→    typeof responseData === "object" &&
    40→    "message" in responseData &&
    41→    typeof responseData.message === "string"
    42→      ? responseData.message
    43→      : null) || axoisErr.message;
    44→
    45→  return {
    46→    success: false,
    47→    error: actualErrorMessage,
    48→    raw_response: responseData,
    49→  };
    50→};
