    52→export async function createImageGenerationAction({
    53→  prompt,
    54→  modelName,
    55→  aspect_ratio = "1:1",
    56→}: CreateImageGenerationInput) {
    57→  try {
    58→    const session = await auth.api.getSession({
    59→      headers: await headers(),
    60→    });
    61→
    62→    if (!session?.user?.id) {
    63→      // [error] Missing auth context
    64→      logger.error("[error] user authentication failed - no user or userId");
    65→      throw new Error(ErrorsMessagesForAPIs.USER_NOT_AUTHENTICATED);
    66→    }
    67→
    68→    const userId = session.user.id;
    69→
    70→    // [step] Create form data payload (aligned with client behavior)
    71→    const formData = new FormData();
    72→    formData.append("prompt", prompt);
    73→    formData.append("aspect_ratio", aspect_ratio);
    74→    formData.append("modelName", modelName); // Dynamic model from autoModelSuggest
    75→    formData.append("provider", ModelProvider.REPLICATE); // From model config
    76→    formData.append("num_outputs", "1");
    77→    formData.append("isAgent", "true"); // Flag to identify agent-generated images
    78→
    79→    // [step] Resolve API URL
    80→    const reqHeaders = await headers();
    81→    const origin = reqHeaders.get("origin") || reqHeaders.get("x-url");
    82→    const baseUrl = origin || env.NEXT_PUBLIC_SERVER_URL;
    83→    const apiUrl = `${baseUrl}/api/venus-9/v2/image`;
    84→
    85→    // [step] Forward auth cookies
    86→    const cookieStore = await cookies();
    87→    const cookieHeader = cookieStore.toString();
    88→
    89→    // [step] Submit image generation request
    90→    const response = await axios.post(apiUrl, formData, {
    91→      headers: {
    92→        "Content-Type": "multipart/form-data",
    93→        // Forward authentication cookies
    94→        Cookie: cookieHeader,
    95→      },
    96→    });
    97→
    98→    const result = response.data;
    99→
   100→    if (result.success && result.data.specialId) {
   101→      return {
   102→        success: true,
   103→        predictionId: result.data.specialId,
   104→        status: result.data.status,
   105→        model: modelName,
   106→        prompt,
   107→        aspect_ratio,
   108→      };
   109→    }
   110→    // [error] API indicated failure
   111→    logger.error(
   112→      `[error] image generation API call failed: ${JSON.stringify(result)}`,
   113→    );
   114→    throw new Error(result.message || "Failed to create image generation");
   115→  } catch (error) {
   116→    // [error] Unexpected exception
   117→    const errorMsg = error instanceof Error ? error.message : String(error);
   118→    logger.error(`[error] createImageGenerationAction failed: ${errorMsg}`);
   119→
   120→    // Log additional axios error details if available
   121→    if (axios.isAxiosError(error)) return handleAxiosError(error as AxiosError);
   122→
   123→    return {
   124→      success: false,
   125→      error: error instanceof Error ? error.message : "Unknown error occurred",
   126→    };
   127→  }
   128→}
