   130→export async function generateImageWithPollingAction({
   131→  prompt,
   132→  modelName,
   133→  aspect_ratio = "1:1",
   134→}: GenerateImageWithPollingInput) {
   135→  try {
   136→    const start = Date.now();
   137→    const session = await auth.api.getSession({
   138→      headers: await headers(),
   139→    });
   140→    const userId = session?.user?.id;
   141→
   142→    // Calculate credits before generation
   143→    const { modelCredits, totalCredits } = calculateImageCredits(modelName, 1);
   144→
   145→    const creationResult = await createImageGenerationAction({
   146→      prompt,
   147→      modelName,
   148→      aspect_ratio,
   149→    });
   150→
   151→    if (!creationResult.success) {
   152→      // [error] Creation failed
   153→      logger.error(`[error] image creation failed: ${creationResult.error}`);
   154→      return creationResult;
   155→    }
   156→
   157→    // @ts-expect-error - predictionId exists in the creationResult
   158→    const predictionId = creationResult.predictionId;
   159→
   160→    const eventProperties = {
   161→      model: modelName,
   162→      provider: ModelProvider.REPLICATE,
   163→      predictionId,
   164→      duration_ms: Date.now() - start,
   165→      status: "created",
   166→      tool: "image-generator",
   167→    };
   168→
   169→    // Capture creation timing to PostHog (server-side)
   170→    // Note: Completion will be tracked client-side
   171→    try {
   172→      await createServerEvent(
   173→        "model_generation",
   174→        String(userId ?? ""),
   175→        eventProperties,
   176→      );
   177→    } catch (phErr: any) {
   178→      // PostHog capture failed silently
   179→    }
   180→
   181→    // Return immediately with predictionId for client-side polling
   182→    return {
   183→      success: true,
   184→      predictionId,
   185→      status: "succeeded",
   186→      output: {
   187→        predictionId,
   188→        provider: "replicate",
   189→      },
   190→      model: modelName,
   191→      prompt,
   192→      aspect_ratio,
   193→      credits: modelCredits,
   194→      totalCredits,
   195→    };
   196→  } catch (error) {
   197→    // [error] Unexpected exception in polling controller
   198→    const errorMsg = error instanceof Error ? error.message : String(error);
   199→    logger.error(`[error] generateImageWithPollingAction failed: ${errorMsg}`);
   200→    if (axios.isAxiosError(error)) return handleAxiosError(error as AxiosError);
   201→    return {
   202→      success: false,
   203→      error: error instanceof Error ? error.message : "Unknown error occurred",
   204→    };
   205→  }
   206→}
