   208→export async function generateVideoWithPollingAction({
   209→  prompt,
   210→  modelName,
   211→  image_url,
   212→  aspect_ratio = "16:9",
   213→  duration,
   214→  resolution,
   215→  negative_prompt,
   216→  generate_audio = true,
   217→}: GenerateVideoWithPollingInput) {
   218→  try {
   219→    const start = Date.now();
   220→    const session = await auth.api.getSession({
   221→      headers: await headers(),
   222→    });
   223→    const userId = session?.user?.id;
   224→    if (!userId) {
   225→      // [error] Missing auth context
   226→      logger.error("[error] user authentication failed - no user or userId");
   227→      throw new Error(ErrorsMessagesForAPIs.USER_NOT_AUTHENTICATED);
   228→    }
   229→
   230→    // Get model configuration to determine variant and default values
   231→    const baseModel = modelName as unknown as VideoModel;
   232→    const modelConfig = frontendVideoModelConfig[baseModel];
   233→    if (!modelConfig) {
   234→      // [error] Missing model config
   235→      logger.error("[error] model configuration not found", { modelName });
   236→      throw new Error(`Model configuration not found for: ${modelName}`);
   237→    }
   238→
   239→    // Determine the correct model variant (text-to-video or image-to-video)
   240→    const hasImage = image_url && image_url.trim() !== "";
   241→    const modelVariant = hasImage
   242→      ? modelConfig.imageToVideoVariant
   243→      : modelConfig.textToVideoVariant;
   244→
   245→    // Calculate credits before generation
   246→    const { modelCredits, totalCredits } = calculateVideoCredits(
   247→      modelVariant,
   248→      {
   249→        duration,
   250→        resolution,
   251→        generate_audio,
   252→      },
   253→      `video-gen-${Date.now()}`,
   254→    );
   255→
   256→    // Build Fal proxy target URL like the client does (provider/modelVariant)
   257→    const requestLink = `${modelConfig.provider}/${modelVariant}`;
   258→
   259→    // Submit via Fal proxy (handles credits, auth, webhooks)
   260→    const reqHeaders = await headers();
   261→    const origin = reqHeaders.get("origin") || reqHeaders.get("x-url");
   262→    const baseUrl = origin || env.NEXT_PUBLIC_SERVER_URL;
   263→    const apiUrl = `${baseUrl}/api/venus-9/videos`;
   264→
   265→    // Build request body with default values from model config
   266→    const requestBody = {
   267→      prompt,
   268→      toolUniqueName: "video-generator",
   269→      modelUniqueId: modelVariant, // Use the resolved variant
   270→      aspect_ratio,
   271→      provider: modelConfig.provider,
   272→      isAgent: true, // Flag to identify agent-generated videos for deterministic S3 keys
   273→      ...(image_url && { image_url }),
   274→      // Explicit overrides from caller (if provided)
   275→      ...(duration && { duration }),
   276→      ...(resolution && { resolution }),
   277→      ...(negative_prompt && { negative_prompt }),
   278→      // Add generate_audio (required for VEO 3.1 and similar models)
   279→      generate_audio,
   280→      // Add default values for required fields from model config
   281→      ...(modelConfig.ui.fields.duration && {
   282→        duration: duration || modelConfig.ui.fields.duration.default || "5",
   283→      }),
   284→      ...(modelConfig.ui.fields.resolution && {
   285→        resolution:
   286→          resolution || modelConfig.ui.fields.resolution.default || "1080p",
   287→      }),
   288→      ...(modelConfig.ui.fields.negative_prompt && {
   289→        negative_prompt:
   290→          negative_prompt ||
   291→          modelConfig.ui.fields.negative_prompt.default ||
   292→          "",
   293→      }),
   294→    };
   295→
   296→    // step 4 is forward auth cookies
   297→    const cookieStore = await cookies();
   298→    const cookieHeader = cookieStore.toString();
   299→
   300→    // step 5 is submit background remover request
   301→    const response: AxiosResponse<unknown> = await axios.post(
   302→      apiUrl,
   303→      requestBody,
   304→      {
   305→        headers: {
   306→          "Content-Type": "application/json",
   307→          // Forward authentication cookies
   308→          Cookie: cookieHeader,
   309→        },
   310→      },
   311→    );
   312→
   313→    const responseData = response.data as {
   314→      data?: { specialId?: string };
   315→      request_id?: string;
   316→      requestId?: string;
   317→    };
   318→    const predictionId =
   319→      responseData?.data?.specialId ||
   320→      responseData?.request_id ||
   321→      responseData?.requestId ||
   322→      undefined;
   323→
   324→    const eventProperties = {
   325→      model: modelName,
   326→      provider: modelConfig.provider,
   327→      predictionId,
   328→      duration_ms: Date.now() - start,
   329→      status: "succeeded",
   330→      tool: "video-generator",
   331→      requestLink,
   332→    };
   333→
   334→    // Capture submission timing to PostHog (server-side)
   335→    try {
   336→      await createServerEvent(
   337→        "model_generation",
   338→        String(userId ?? ""),
   339→        eventProperties,
   340→      );
   341→    } catch (phErr: any) {
   342→      // PostHog capture failed silently
   343→    }
   344→
   345→    return {
   346→      success: true,
   347→      status: "succeeded",
   348→      model: modelName,
   349→      prompt,
   350→      image_url,
   351→      aspect_ratio,
   352→      credits: modelCredits,
   353→      totalCredits,
   354→      output: {
   355→        predictionId,
   356→        requestLink,
   357→      },
   358→    };
   359→  } catch (error) {
   360→    // [error] Unexpected exception in video polling controller
   361→    logger.error("[error] generateVideoWithPollingAction failed", error);
   362→    if (axios.isAxiosError(error)) return handleAxiosError(error as AxiosError);
   363→
   364→    return {
   365→      success: false,
   366→      error: error instanceof Error ? error.message : "Unknown error occurred",
   367→    };
   368→  }
   369→}
