   371→export async function GenerateEditImageAction({
   372→  prompt,
   373→  image_urls,
   374→  model_name = "nano_banana_pro",
   375→}: GenerateEditImageWithPollingInput) {
   376→  // [info] Start: image edit generation with polling (multi-image)
   377→
   378→  try {
   379→    const start = Date.now();
   380→    // step 1 is authenticate user
   381→    const session = await auth.api.getSession({
   382→      headers: await headers(),
   383→    });
   384→    const userId = session?.user?.id;
   385→    if (!userId) {
   386→      // [error] Missing auth context
   387→      logger.error("[error] user authentication failed - no user or userId");
   388→      throw new Error(ErrorsMessagesForAPIs.USER_NOT_AUTHENTICATED);
   389→    }
   390→
   391→    // [info] Authenticated
   392→
   393→    // step 2 is create JSON payload for unified replicate API (multi-image)
   394→    const requestBody = {
   395→      modelName: "image-editor", // Required: model identifier
   396→      prompt,
   397→      images: image_urls, // Changed: input_images → images
   398→      model_name,
   399→      auto_upscale: false, // Optional: can add if needed
   400→    };
   401→
   402→    // step 3 is resolve API URL (prefer request origin for cookie domain)
   403→    const reqHeaders = await headers();
   404→    const origin = reqHeaders.get("origin") || reqHeaders.get("x-url");
   405→    const baseUrl = origin || env.NEXT_PUBLIC_SERVER_URL;
   406→    const apiUrl = `${baseUrl}/api/venus-9/tools/replicate`;
   407→    // step 4 is forward auth cookies
   408→    const cookieStore = await cookies();
   409→    const cookieHeader = cookieStore.toString();
   410→
   411→    // step 5 is submit image edit request
   412→    const response = await axios.post(apiUrl, requestBody, {
   413→      headers: {
   414→        "Content-Type": "application/json",
   415→        // Forward authentication cookies
   416→        Cookie: cookieHeader,
   417→      },
   418→    });
   419→
   420→    const result = response.data;
   421→
   422→    // Accept 202 response and extract id from data.specialId (unified API format)
   423→    const isAccepted = response.status === 202 || response.status === 200;
   424→    const apiPredictionId = result?.data?.specialId;
   425→
   426→    if (isAccepted && apiPredictionId) {
   427→      const predictionId = apiPredictionId;
   428→
   429→      // step 6 is poll until completion using centralized function
   430→
   431→      // Reuse existing cookies for polling request
   432→
   433→      try {
   434→        const prediction = await pollPrediction(predictionId, {
   435→          baseUrl,
   436→          provider: ModelProvider.REPLICATE,
   437→          cookie: cookieHeader,
   438→          maxAttempts: 60, // 5 minutes max
   439→          initialDelayMs: 2000, // 2 seconds for testing (changed from 15s)
   440→          totalTimeoutMs: 5 * 60 * 1000, // 5 minutes total
   441→          fixedInterval: true, // Use fixed 2s interval for testing direct Replicate API impact
   442→        });
   443→
   444→        const eventProperties = {
   445→          model: model_name,
   446→          provider: ModelProvider.REPLICATE,
   447→          predictionId,
   448→          duration_ms: Date.now() - start,
   449→          status: prediction.status,
   450→          tool: "image-edit",
   451→        };
   452→
   453→        // Capture timing to PostHog (server-side)
   454→        try {
   455→          await createServerEvent(
   456→            "model_generation",
   457→            String(userId ?? ""),
   458→            eventProperties,
   459→          );
   460→        } catch (phErr: any) {
   461→          // PostHog capture failed silently
   462→        }
   463→
   464→        if (prediction.status === "succeeded") {
   465→          // step 12 is return the final result
   466→          const finalResult = {
   467→            success: true,
   468→            predictionId,
   469→            status: "succeeded",
   470→            output: prediction.output || [],
   471→            model_name,
   472→            prompt,
   473→            image_urls,
   474→            created_at: prediction.created_at,
   475→          };
   476→
   477→          return finalResult;
   478→        }
   479→        if (prediction.status === "failed") {
   480→          // [error] Prediction indicates failure
   481→          logger.error(
   482→            "[error] image edit generation failed",
   483→            prediction.error,
   484→          );
   485→          return {
   486→            success: false,
   487→            error: prediction.error || "Image edit generation failed",
   488→          };
   489→        }
   490→        // [error] Unexpected status
   491→        logger.error("[error] unexpected prediction status", prediction.status);
   492→        return {
   493→          success: false,
   494→          error: `Unexpected prediction status: ${prediction.status}`,
   495→        };
   496→      } catch (pollError) {
   497→        // [error] Polling failed
   498→        logger.error("[error] polling failed", pollError);
   499→        try {
   500→          await createServerEvent("model_generation", String(userId ?? ""), {
   501→            model: model_name,
   502→            provider: ModelProvider.REPLICATE,
   503→            predictionId,
   504→            duration_ms: Date.now() - start,
   505→            status: "polling_failed",
   506→            tool: "image-edit",
   507→          });
   508→        } catch (phErr: any) {
   509→          // PostHog capture failed silently
   510→        }
   511→        return {
   512→          success: false,
   513→          error:
   514→            pollError instanceof Error ? pollError.message : "Polling failed",
   515→        };
   516→      }
   517→    } else {
   518→      // [error] API indicated failure
   519→      logger.error("[error] unified replicate API call failed", result);
   520→      throw new Error(
   521→        result.message || "Failed to create image edit generation",
   522→      );
   523→    }
   524→  } catch (error) {
   525→    // [error] Unexpected exception
   526→    logger.error("[error] generateEditImageWithPollingAction failed", error);
   527→
   528→    // Log additional axios error details if available
   529→    if (axios.isAxiosError(error)) return handleAxiosError(error as AxiosError);
   530→
   531→    return {
   532→      success: false,
   533→      error: error instanceof Error ? error.message : "Unknown error occurred",
   534→    };
   535→  }
   536→}
