   392→function extractTextFromUiMessage(message: UIMessage): string | undefined {
   393→  return extractTextFromParts(message.parts);
   394→}
   395→
   396→function extractTextFromParts(parts: UIMessage["parts"]): string | undefined {
   397→  const chunks: string[] = [];
   398→  for (const part of parts) {
   399→    if (part.type === "text") {
   400→      chunks.push(part.text);
   401→    }
   402→  }
   403→  const text = chunks.join("");
   404→  return text.trim().length ? text : undefined;
   405→}
   406→
   407→function extractLatestUserTextFromUiMessages(
   408→  messages: UIMessage[],
   409→): string | undefined {
   410→  for (let i = messages.length - 1; i >= 0; i -= 1) {
   411→    const msg = messages[i];
   412→    if (msg.role !== "user") continue;
   413→    const text = extractTextFromUiMessage(msg);
   414→    if (text) return text;
   415→  }
   416→  return;
   417→}
   418→
   419→function summarizeParts(parts: UIMessage["parts"]): string {
   420→  const counts = new Map<string, number>();
   421→  for (const part of parts) {
   422→    counts.set(part.type, (counts.get(part.type) ?? 0) + 1);
   423→  }
   424→  const summary = [...counts.entries()]
   425→    .map(([type, count]) => `${type}:${count}`)
   426→    .join(", ");
   427→
   428→  return summary.length ? `parts(${summary})` : "parts(empty)";
   429→}
