    19→// Create axios instance for Replicate API
    20→const replicateInstance = axios.create({
    21→  baseURL: "https://api.replicate.com/v1",
    22→  headers: {
    23→    Authorization: `Token ${env.REPLICATE_API_TOKEN}`,
    24→    "Content-Type": "application/json",
    25→  },
    26→});
    27→
    28→// Regex for converting upscale factor format (e.g., "2x" to "x2")
    29→const UPSCALE_FACTOR_REGEX = /^(\d+)x$/;
    30→
    31→/**
    32→ * Unified AI processing API
    33→ * Handles all AI operations through a single endpoint
    34→ */
    35→export async function POST(req: NextRequest): Promise<NextResponse> {
    36→  const requestId: string = crypto.randomUUID();
    37→  let userId: string | undefined;
    38→
    39→  try {
    40→    // Step 1: Authenticate user
    41→    logger.info(`[${requestId}] Authenticating user`);
    42→    const authResult = await authenticateUser(requestId);
    43→    userId = authResult.id;
    44→
    45→    if (!userId) {
    46→      logger.warn(`[${requestId}] Authentication failed - no user ID`);
    47→      return NextResponse.json(
    48→        {
    49→          success: false,
    50→          error: "Unauthorized",
    51→        },
    52→        { status: 401 },
    53→      );
    54→    }
    55→
    56→    // Step 2: Parse request body
    57→    logger.info(`[${requestId}] Parsing request body`);
    58→    const body: AIProcessRequest = await req.json();
    59→    const { action, payload } = body;
    60→
    61→    if (!action) {
    62→      logger.warn(`[${requestId}] Missing action type in request`);
    63→      return NextResponse.json(
    64→        {
    65→          success: false,
    66→          error: "Action type is required",
    67→        },
    68→        { status: 400 },
    69→      );
    70→    }
    71→
    72→    if (!payload) {
    73→      logger.warn(`[${requestId}] Missing payload in request`);
    74→      return NextResponse.json(
    75→        {
    76→          success: false,
    77→          error: "Payload is required",
    78→        },
    79→        { status: 400 },
    80→      );
    81→    }
    82→
    83→    // Step 3: Get tool configuration
    84→    logger.info(`[${requestId}] Getting tool config for ${action}`);
    85→    let toolConfig = AI_TOOLS_CONFIG[action];
    86→
    87→    if (!toolConfig) {
    88→      logger.error(`[${requestId}] Unsupported action type: ${action}`);
    89→      return NextResponse.json(
    90→        {
    91→          success: false,
    92→          error: `Unsupported action type: ${action}`,
    93→        },
    94→        { status: 400 },
    95→      );
    96→    }
    97→
    98→    // Handle multi-model tools (upscale with model selection)
    99→    if (action === "upscale" && payload.parameters) {
   100→      const params = payload.parameters as Record<string, unknown>;
   101→      const selectedModel = params.model as string | undefined;
   102→
   103→      if (selectedModel) {
   104→        const upscalerModel = UPSCALER_MODELS[selectedModel];
   105→
   106→        if (upscalerModel) {
   107→          logger.info(
   108→            `[${requestId}] Using upscaler model: ${selectedModel} (${upscalerModel.name})`,
   109→          );
   110→          toolConfig = {
   111→            ...toolConfig,
   112→            model: upscalerModel.model,
   113→            creditCost: upscalerModel.creditCost,
   114→          };
   115→        }
   116→      }
   117→    }
   118→
   119→    // Step 4: Prepare Replicate prediction input
   120→    logger.info(
   121→      `[${requestId}] Preparing prediction input for action: ${action}`,
   122→    );
   123→    const input = prepareInput(action, payload);
   124→
   125→    // Step 5: Create prediction
   126→    logger.info(`[${requestId}] Creating prediction for user: ${userId}`);
   127→
   128→    const creditResult = await deductCreditsWithLedger(
   129→      userId,
   130→      requestId, // Use requestId as jobId in the ledger
   131→      toolConfig.creditCost,
   132→      "IMAGE_EDITOR",
   133→      { modelName: toolConfig.model },
   134→    );
   135→
   136→    if (!creditResult.success) {
   137→      logger.error(
   138→        `[${requestId}] Credit deduction failed: ${creditResult.message}`,
   139→      );
   140→      throw new Error(
   141→        creditResult.message || ErrorsMessagesForAPIs.ERROR_DEDUCTING_CREDITS,
   142→      );
   143→    }
   144→
   145→    logger.info(
   146→      `[${requestId}] Successfully deducted ${toolConfig.creditCost} credits from user ${userId}`,
   147→    );
   148→    // Handle cases where version is null, undefined, or empty
   149→    const predictionPayload: {
   150→      input: Record<string, unknown>;
   151→      version?: string;
   152→    } = { input };
   153→
   154→    // Only add version if it exists
   155→    if (toolConfig.version && toolConfig.version.trim() !== "") {
   156→      predictionPayload.version = `${toolConfig.model}:${toolConfig.version}`;
   157→    } else {
   158→      // Just use model without version
   159→      predictionPayload.version = toolConfig.model;
   160→    }
   161→
   162→    logger.info(`[${requestId}] Sending request to Replicate`, {
   163→      action,
   164→      model: toolConfig.model,
   165→      version: toolConfig.version || "Not specified",
   166→      userId,
   167→    });
   168→
   169→    const response = await replicateInstance.post(
   170→      "/predictions",
   171→      predictionPayload,
   172→    );
   173→    const prediction = response.data;
   174→
   175→    logger.info(`[${requestId}] Prediction created successfully`, {
   176→      predictionId: prediction.id,
   177→      status: prediction.status,
   178→      action,
   179→      userId,
   180→    });
   181→
   182→    // Step 7: Return response
   183→    return NextResponse.json(
   184→      {
   185→        success: true,
   186→        message: "AI processing request submitted successfully",
   187→        data: {
   188→          requestId: prediction.id,
   189→          status: prediction.status,
   190→          action,
   191→          creditsUsed: toolConfig.creditCost,
   192→        },
   193→      } as AIProcessResponse,
   194→      { status: 202 },
   195→    );
   196→  } catch (error: unknown) {
   197→    const errorMessage = error instanceof Error ? error.message : String(error);
   198→    const errorName = error instanceof Error ? error.name : "UnknownError";
   199→
   200→    logger.error(
   201→      `[${requestId || "UNKNOWN"}] AI processing error: ${errorMessage}`,
   202→    );
   203→    logger.error(`[${requestId || "UNKNOWN"}] Error details`, {
   204→      name: errorName,
   205→      message: errorMessage,
   206→      stack: error instanceof Error ? error.stack : undefined,
   207→      userId: userId || "unknown",
   208→    });
   209→
   210→    // Check if it's an Axios error with response data
   211→    if (axios.isAxiosError(error) && error.response?.data) {
   212→      const responseData = error.response.data;
   213→      const statusCode = error.response.status;
   214→
   215→      logger.error(
   216→        `[${requestId || "UNKNOWN"}] Replicate API error - Status: ${statusCode}`,
   217→      );
   218→      logger.error(`[${requestId || "UNKNOWN"}] Replicate API response`, {
   219→        status: statusCode,
   220→        error:
   221→          responseData?.error || responseData?.detail || "Unknown API error",
   222→        userId: userId || "unknown",
   223→      });
   224→
   225→      // Return the specific error message from Replicate
   226→      const errorMessageReplicateApi =
   227→        error.response.data.detail ||
   228→        error.response.data.error ||
   229→        "AI service error";
   230→      return NextResponse.json(
   231→        { success: false, error: errorMessageReplicateApi },
   232→        { status: error.response.status || 503 },
   233→      );
   234→    }
   235→
   236→    // Handle authentication errors specifically
   237→    if (error instanceof Error && error.message.includes("Unauthorized")) {
   238→      return NextResponse.json(
   239→        { success: false, error: "Unauthorized" },
   240→        { status: 401 },
   241→      );
   242→    }
   243→
   244→    // Handle other errors
   245→    const finalErrorMessage =
   246→      error instanceof Error ? error.message : "Internal server error";
   247→    return NextResponse.json(
   248→      {
   249→        success: false,
   250→        error: finalErrorMessage,
   251→      },
   252→      { status: 500 },
   253→    );
   254→  }
   255→}
