   257→/**
   258→ * Prepare input for Replicate based on action type
   259→ */
   260→function prepareInput(
   261→  action: AIActionType,
   262→  payload: Record<string, unknown>,
   263→): Record<string, unknown> {
   264→  const { imageData, maskData, parameters } = payload;
   265→  const params = parameters as Record<string, unknown>;
   266→  const images = imageData as string[] | string;
   267→
   268→  switch (action) {
   269→    case "generate-image":
   270→      return {
   271→        prompt: params.prompt,
   272→        aspect_ratio: params.aspect_ratio || "3:2",
   273→        output_format: params.output_format || "webp",
   274→        output_quality: params.output_quality || 90,
   275→        prompt_strength: params.prompt_strength || 0.8,
   276→      };
   277→
   278→    case "remove-bg":
   279→      return {
   280→        image: images,
   281→        model: params.model_type || "general",
   282→        alpha_matting: params.alpha_matting,
   283→        alpha_matting_foreground_threshold:
   284→          params.alpha_matting_foreground_threshold || 0.27,
   285→        alpha_matting_background_threshold:
   286→          params.alpha_matting_background_threshold || 0.1,
   287→      };
   288→
   289→    case "inpaint":
   290→      return {
   291→        image: images,
   292→        mask: maskData,
   293→        prompt: params.prompt,
   294→        aspect_ratio: params.aspect_ratio, // Preserve input image aspect ratio
   295→        guidance: params.guidance || 60,
   296→        steps: params.steps || 50,
   297→        output_format: params.output_format || "png",
   298→        safety_tolerance: params.safety_tolerance || 2,
   299→      };
   300→
   301→    case "resize":
   302→      return {
   303→        input_image: images,
   304→        aspect_ratio: params.aspect_ratio || "1:1",
   305→        quality: params.quality || "high",
   306→        replicate_api_token: env.REPLICATE_API_TOKEN,
   307→        openai_api_key: env.OPENAI_API_KEY,
   308→      };
   309→
   310→    case "edit-elements": {
   311→      return {
   312→        image: images,
   313→        output_format: "png",
   314→        description:
   315→          "Precisely remove the foreground object layer while preserving all natural shadows, lighting gradients, and background textures. Do not remove or alter shadows. Maintain realistic depth and illumination",
   316→        output_quality: 100,
   317→      };
   318→    }
   319→
   320→    case "edit-text": {
   321→      return {
   322→        image_input: images,
   323→        prompt: params.prompt,
   324→        output_format: "png",
   325→        resolution: "4K",
   326→        aspect_ratio: "match_input_image",
   327→      };
   328→    }
   329→
   330→    case "upscale": {
   331→      const modelId = params.model as string | undefined;
   332→
   333→      // Different models have different input parameters
   334→      switch (modelId) {
   335→        case "topaz-labs":
   336→          // Topaz Labs specific parameters
   337→          return {
   338→            image: images,
   339→            enhance_model: params.enhance_model || "Standard V2",
   340→            upscale_factor: params.upscale_factor || "2x",
   341→          };
   342→
   343→        case "google-upscaler": {
   344→          // Google Upscaler specific parameters - requires x2, x4 format
   345→          const upscaleFactor =
   346→            (typeof params.upscale_factor === "string"
   347→              ? params.upscale_factor
   348→              : null) || "2x";
   349→          // Convert "2x" to "x2", "4x" to "x4" for Google upscaler
   350→          const convertedFactor = upscaleFactor.replace(
   351→            UPSCALE_FACTOR_REGEX,
   352→            "x$1",
   353→          );
   354→          return {
   355→            image: images,
   356→            upscale_factor: convertedFactor,
   357→          };
   358→        }
   359→
   360→        default:
   361→          // Recraft Crisp (default) - simple parameters
   362→          return {
   363→            image: images,
   364→            upscale_factor: params.upscale_factor || "2x",
   365→          };
   366→      }
   367→    }
   368→
   369→    case "image-to-image": {
   370→      // Simple logic: single image -> image field, multiple images -> images field only
   371→      if (Array.isArray(images) && images.length > 1) {
   372→        // Multiple images: use images field only
   373→        logger.info(
   374→          `Processing multiple images for image-to-image - Count: ${images.length}`,
   375→        );
   376→        return {
   377→          images,
   378→          prompt: params.prompt || "",
   379→          model_name: params.model || "flux_kontext_max",
   380→        };
   381→      }
   382→      // Single image: use image field only
   383→      const singleImage = Array.isArray(images) ? images[0] : images;
   384→      logger.info(
   385→        `Processing single image for image-to-image - Has image: ${!!singleImage}`,
   386→      );
   387→      return {
   388→        input_image: singleImage,
   389→        prompt: params.prompt || "",
   390→        model_name: params.model || "flux_kontext_pro",
   391→        replicate_api_key: env.REPLICATE_API_TOKEN,
   392→        openai_api_key: env.OPENAI_API_KEY,
   393→      };
   394→    }
   395→
   396→    default:
   397→      throw new Error(`Unsupported action type: ${action}`);
   398→  }
   399→}
